import type {
  _OverlayTooltipGeometryTypes as GeometryTypes,
  _OverlayTooltipState as TooltipState,
} from '@dynatrace/strato-components/charts';

/**
 * Builds the full TooltipState object for the geo map context.
 *
 * Centralises the state shape so that both the event-side
 * (`useOverlayEvents`) and the sync-side (`useGeoTooltipSync`)
 * produce the exact same structure.
 */
export const buildGeoTooltipState = ({
  absoluteX,
  absoluteY,
  relativeX,
  relativeY,
  pinned,
  geometry,
  metadata,
}: {
  absoluteX: number;
  absoluteY: number;
  relativeX: number;
  relativeY: number;
  pinned: boolean;
  geometry: GeometryTypes;
  metadata: unknown[] | undefined;
}): TooltipState =>
  ({
    absoluteX,
    absoluteY,
    relativeX,
    relativeY,
    percentX: 0,
    percentY: 0,
    inBounds: true,
    pinned,
    activeSeries: null,
    data: {
      geometry,
      series: [],
      metadata,
    },
  } as TooltipState);
